arguments.file_text:
@namespace sv_75b1e565445f4517bdfc377dc5e23239.Components.Pages.Apply

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var state = GetStepState(step);
        <div class="step-item text-center flex-fill @state" role="button"
             @onclick="() => OnStepClicked(step)">
            <div class="step-circle mx-auto @state">
                @if (state == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <div class="step-label mt-1 small">@StepNames[step]</div>
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames =
