</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private void UpdateField(int index, string? company = null, string? title = null, string? description = null)
    {
        if (company is not null) Entries[index].Company = company;
        if (title is not null) Entries[index].Title = title;
        if (description is not null) Entries[index].Description = description;
    }

    private void UpdateStartDate(int index, string? value)
    {
        Entries[index].StartDate = DateTime.TryParse(value, out var d) ? d : null;
    }

    private void UpdateEndDate(int index, string? value)
    {
        Entries[index].EndDate = DateTime.TryParse(value, out var d) ? d : null;
    }

    private void ToggleCurrent(int index, bool isCurrent)
    {
        Entries[index].IsCurrent = isCurrent;
        if (isCurrent) Entries[index].EndDate = null;
    }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate is null)
            {
                ValidationError = "Company, job title, and start date are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

