@namespace sv_75b1e565445f4517bdfc377dc5e23239.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input class="form-control" @bind="FullName" @bind:event="oninput" placeholder="Enter your full name" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
           @bind="Email" @bind:event="oninput" placeholder="you@example.com" />
    @if (EmailError is not null)
    {
        <div class="invalid-feedback">@EmailError</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Address" @bind:event="oninput"
              placeholder="Street, City, State, ZIP"></textarea>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? ValidationError;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ValidationError = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
        }
        finally
        {
            IsValidating = false;
        }
    }
}

