<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input class="form-control" value="@Entries[index].Company"
                           @onchange="e => UpdateField(index, company: e.Value?.ToString())" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input class="form-control" value="@Entries[index].Title"
                           @onchange="e => UpdateField(index, title: e.Value?.ToString())" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@FormatDate(Entries[index].StartDate)"
                           @onchange="e => UpdateStartDate(index, e.Value?.ToString())" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@FormatDate(Entries[index].EndDate)"
                           disabled="@Entries[index].IsCurrent"
                           @onchange="e => UpdateEndDate(index, e.Value?.ToString())" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@index"
                               checked="@Entries[index].IsCurrent"
                               @onchange="e => ToggleCurrent(index, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" value="@Entries[index].Description"
                          @onchange="e => UpdateField(index, description: e.Value?.ToString())"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private void UpdateField(int index, string? company = null, string? title = null, string? description = null)
    {
        if (company is not null) Entries[index].Company = company;
        if (title is not null) Entries[index].Title = title;
        if (description is not null) Entries[index].Description = description;
    }

    private void UpdateStartDate(int index, string? value)
    {
        Entries[index].StartDate = DateTime.TryParse(value, out var d) ? d : null;
    }

    private void UpdateEndDate(int index, string? value)
    {
        Entries[index].EndDate = DateTime.TryParse(value, out var d) ? d : null;
    }

    private void ToggleCurrent(int index, bool isCurrent)
    {
        Entries[index].IsCurrent = isCurrent;
        if (isCurrent) Entries[index].EndDate = null;
    }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate is null)
            {
                ValidationError = "Company, job title, and start date are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

