@namespace sv_75b1e565445f4517bdfc377dc5e23239.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>
            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input class="form-control" value="@References[index].Name"
                           @onchange="e => UpdateField(index, name: e.Value?.ToString())" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input class="form-control" value="@References[index].Relationship"
                           @onchange="e => UpdateField(index, relationship: e.Value?.ToString())" />
                </div>
            </div>
            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@References[index].Email"
                           @onchange="e => UpdateField(index, email: e.Value?.ToString())" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@References[index].Phone"
                           @onchange="e => UpdateField(index, phone: e.Value?.ToString())" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }

    private void UpdateField(int index, string? name = null, string? relationship = null,
                             string? email = null, string? phone = null)
    {
        if (name is not null) References[index].Name = name;
        if (relationship is not null) References[index].Relationship = relationship;
        if (email is not null) References[index].Email = email;
        if (phone is not null) References[index].Phone = phone;
    }

    private void AddReference()
    {
        if (References.Count < 3) References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index) => References.RemoveAt(index);

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ValidationError = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync(References);
    }
}

