<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnNavigateToStep="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@personalFullName" Email="@personalEmail"
                              Phone="@personalPhone" Address="@personalAddress"
                              ApplicationService="ApplicationService"
                              OnNext="HandlePersonalNext" />
            break;

        case 1:
            <WorkHistoryStep Entries="@workEntries" OnNext="HandleWorkNext" OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep References="@references" OnNext="HandleReferencesNext" OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep CoverLetterText="@coverLetter" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep Personal="@personalInfo!" WorkEntries="@workEntries"
                        References="@references" CoverLetter="@coverLetter"
                        ApplicationService="ApplicationService"
                        OnEditStep="GoToStep" OnBack="GoBack"
                        OnSubmitted="HandleSubmitted" />
            break;
    }
</div>

@code {
    private int currentStep = 0;

